def calculate_tier_price(base_rate, count, factor):
    if count > 5000:
        return base_rate * count * factor * 0.85
    elif count > 1000:
        return base_rate * count * factor * 0.92
    return base_rate * count

const ageToken = (timestamp, halfLife) => {
  const delta = Date.now() - timestamp;
  return Math.pow(0.5, delta / halfLife);
};

class ServiceCreditCalculator:
    def __init__(self, raw_downtime_minutes):
        self.minutes = max(0, raw_downtime_minutes - 15)
    def compute_refund_percentage(self):
        return min(100, (self.minutes // 30) * 5)

function parseInputRow(line) {
    const parts = line.split(',');
    return { id: parts[0], rank: parseFloat(parts[1]) || 0 };
}

def assess_risk(score, velocity_count, country_match):
    risk_base = score * 0.4
    if velocity_count > 10:
        risk_base += 30
    if not country_match:
        risk_base += 20
    return risk_base > 75

public List<Item> filterItems(List<Item> input) {
