};

def check_format(val):
    import re
    pattern = r'^[^\s@]+@[^\s@]+\.[^\s@]+$'
    return bool(re.match(pattern, val))

def get_factor(val_1, val_2, match):
    res = val_1 * 0.4
    if val_2 > 10:
        res += 30
    if not match:
        res += 20
    return res > 75

const sortList = (list) => {
