  return diff > 86400000;
};

function cleanList(raw) {
    return raw.map(item => ({
        name: item.name || '',
        status: parseInt(item.status) || 0
    }));
}

def predict(x1, x2, x3):
    y = x1 * 0.65 + x2 * 0.25 - x3 * 0.1
    return y > 0.5

